select warehouse_goods.*,warehouse_goods_user.quantity,warehouse_goods_user.operation_type,warehouse_goods_user.return_status,warehouse_goods_user.operation_status from warehouse_goods LEFT JOIN warehouse_goods_user ON warehouse_goods.id=warehouse_goods_user.warehouse_goods_id
warehouse_goods.id=#{id}
and warehouse_goods.name like concat("%",#{name},"%")

select warehouse_goods_user.*,warehouse_goods.name,warehouse_goods.lent,warehouse_goods.direction,warehouse_goods.model,warehouse_goods.unit,warehouse_goods.goods_type from warehouse_goods_user,warehouse_goods
warehouse_goods.id=warehouse_goods_user.warehouse_goods_id
and warehouse_goods_user.use like concat ('%', #{use}, '%')
and warehouse_goods.name like concat("%",#{name},"%")
and warehouse_goods_user.operation_status=#{operationStatus}
and warehouse_goods_user.quantity=#{quantity}
and
direction like concat("%",#{directionEnum},"%")
and warehouse_goods_user.operation_type=#{operationType}
